import React, { useEffect } from "react"
import useData, { getInstallments, getPlansData, getTotalAmount } from "../useData"
import useSplitStore from "../useSplitStore"

export function Installment({ dueDateLabel, installment }) {
    return (<button className="flex text-blue-800 bg-blue-200">
        <div>{installment}</div>
        <div>{'due ' + dueDateLabel}</div>
    </button>
    )
}

function Installments() {
    const { totalAmount, selectedPlan, setInstallments } = useSplitStore((s) => s)
    const { data, loading, error, refetch } = useData(getInstallments, {
        loadInitially: false
    })

    // useEffect(() => {
    //     if (selectedPlan && totalAmount) {
    //         refetch(getInstallments)
    //     }
    // }, [selectedPlan, totalAmount])

    // useEffect(() => {
    //     if (data) {
    //         setInstallments(data)
    //     }
    // }, [data])

    if (loading) {
        return <div>Loading...</div>
    }
    if (error) {
        return <div>{error.message}</div>
    }
    if (data) {
        return (
            <div>
                {
                    data.map((installment) => {
                        return (<Installment key={installment.id} {...installment} />)
                    })
                }
            </div>
        )
    }
    return null
}

export default Installments
